<?php
declare(strict_types=1);
require_once dirname(__DIR__,2).'/includes/portal_estudiante_layout.php';require_once dirname(__DIR__,2).'/includes/academico_flujo.php';exigirRol(['usuario']);$id=filter_var($_GET['id']??0,FILTER_VALIDATE_INT,['options'=>['min_range'=>1]])?:0;$pdo=obtenerConexion();$q=$pdo->prepare("SELECT i.*,a.nombre,a.codigo,a.descripcion,s.codigo seccion,CONCAT_WS(' ',d.nombre,d.apellido) docente FROM inscripciones_capacitacion i JOIN asignaturas a ON a.id=i.asignatura_id JOIN capacitacion_secciones s ON s.id=i.seccion_id JOIN usuarios d ON d.id=i.docente_id WHERE i.usuario_id=:u AND i.asignatura_id=:a AND i.estado IN('inscrito','finalizado') LIMIT 1");$q->execute(['u'=>$_SESSION['usuario_id'],'a'=>$id]);$curso=$q->fetch();if(!$curso){http_response_code(403);exit('No tienes acceso a esta capacitación.');}$portal=portalEstudianteCabecera($curso['nombre'],'cursos','Contenido de tu sección '.$curso['seccion'].'.');$q=$pdo->prepare("SELECT c.*,(SELECT estado FROM entregas_contenido e WHERE e.contenido_id=c.id AND e.estudiante_id=:u ORDER BY intento DESC LIMIT 1) entrega_estado,p.visto_at,p.completado_at FROM contenidos c LEFT JOIN progreso_contenido p ON p.contenido_id=c.id AND p.inscripcion_id=:i WHERE c.seccion_id=:s AND c.estado='activo' AND c.activo=1 AND (c.fecha_publicacion IS NULL OR c.fecha_publicacion<=NOW()) ORDER BY c.modulo,c.orden,c.id");$q->execute(['u'=>$_SESSION['usuario_id'],'i'=>$curso['id'],'s'=>$curso['seccion_id']]);$contenidos=$q->fetchAll();$progreso=progresoInscripcion($pdo,(int)$curso['id']);$modulo='';
?><div class="row g-4"><div class="col-lg-8"><div class="card"><div class="card-body"><span class="badge bg-primary"><?=atenea_e($curso['codigo'])?></span><h1 class="h3 mt-3"><?=atenea_e($curso['nombre'])?></h1><p><?=atenea_e($curso['descripcion'])?></p><p><strong>Sección:</strong> <?=atenea_e($curso['seccion'])?> · <strong>Docente:</strong> <?=atenea_e($curso['docente'])?></p><?php foreach($contenidos as$c):if($modulo!==$c['modulo']):$modulo=$c['modulo'];?><h2 class="h5 mt-4 border-bottom pb-2"><?=atenea_e($modulo)?></h2><?php endif;?><a class="d-block border rounded p-3 mb-2 text-decoration-none" href="contenido.php?id=<?=$c['id']?>"><div class="d-flex justify-content-between"><strong><?=atenea_e($c['titulo'])?></strong><span class="badge bg-light text-dark"><?=atenea_e($c['tipo'])?></span></div><small class="text-muted"><?=$c['obligatorio']?'Obligatorio':'Opcional'?><?php if($c['fecha_limite']):?> · Límite <?=date('d/m/Y H:i',strtotime($c['fecha_limite']))?><?php endif;?></small><div class="mt-1"><?php if($c['entrega_estado']):?><span class="badge bg-info"><?=atenea_e($c['entrega_estado'])?></span><?php elseif($c['completado_at']):?><span class="badge bg-success">Completado</span><?php elseif($c['visto_at']):?><span class="badge bg-secondary">Visto</span><?php endif;?></div></a><?php endforeach;?><?php if(!$contenidos):?><p class="text-muted">No hay contenidos publicados para tu sección.</p><?php endif;?></div></div></div><div class="col-lg-4"><div class="card"><div class="card-body"><h2 class="h5">Mi progreso</h2><div class="progress mb-2" style="height:18px"><div class="progress-bar" style="width:<?=$progreso['porcentaje']?>%"><?=$progreso['porcentaje']?>%</div></div><dl class="row small"><dt class="col-8">Contenidos vistos</dt><dd class="col-4"><?=$progreso['contenidos_vistos']?></dd><dt class="col-8">Pendientes</dt><dd class="col-4"><?=$progreso['entregas_pendientes']?></dd><dt class="col-8">Aprobadas</dt><dd class="col-4"><?=$progreso['entregas_aprobadas']?></dd><dt class="col-8">Rechazadas/corrección</dt><dd class="col-4"><?=$progreso['entregas_rechazadas']?></dd><dt class="col-8">Promedio</dt><dd class="col-4"><?=$progreso['promedio']!==null?number_format($progreso['promedio'],2):'—'?></dd></dl><small>Última actividad: <?=atenea_e((string)$progreso['ultima_actividad'])?></small></div></div></div></div><?php portalEstudiantePie();
